solution_code:
#include <iostream>

int perimeter(int w, int h)
{
    return 2 * (w + h);
}

int area(int w, int h)
{
    return w * h;
}

int main()
{
    int w;
    int h;
    std::cin >> w >> h;

    std::cout << "Perimeter: " << perimeter(w, h) << "\n";
    std::cout << "Area: " << area(w, h) << "\n";

    return 0;
}

