solution_code:
#include <iostream>

int scaledSum(int a, int b, int factor)
{
    return (a + b) * factor;
}

int main()
{
    int a;
    int b;
    int factor;
    std::cin >> a >> b >> factor;
    std::cout << "Scaled sum: " << scaledSum(a, b, factor) << "\n";
    return 0;
}
